// src/App.js
import React from "react";
import { BrowserRouter as Router, Routes, Route } from "react-router-dom";
import Page1 from "./pages/Page1";
import Page2 from "./pages/Page2";
import Page3 from "./pages/Page3";
import Page4 from "./pages/Page4";
import Page5 from "./pages/Page5";
import Page6 from "./pages/Page6";
import Page7 from "./pages/Page7";
import Page8 from "./pages/Page8";
import Page9 from "./pages/Page9";
import Page10 from "./pages/Page10";

function App() {
  return (
    <Router>
// In your App.js, make sure you have routes for all pages:
<Routes>
  <Route path="/" element={<SquaresPage pageNumber={1} />} />
  <Route path="/page/2" element={<SquaresPage pageNumber={2} />} />
  <Route path="/page/3" element={<SquaresPage pageNumber={3} />} />
  <Route path="/page/4" element={<SquaresPage pageNumber={4} />} />
  <Route path="/page/5" element={<SquaresPage pageNumber={5} />} />
  <Route path="/page/6" element={<SquaresPage pageNumber={6} />} />
  <Route path="/page/7" element={<SquaresPage pageNumber={7} />} />
  <Route path="/page/8" element={<SquaresPage pageNumber={8} />} />
  <Route path="/page/9" element={<SquaresPage pageNumber={9} />} />
  <Route path="/page/10" element={<SquaresPage pageNumber={10} />} />
  <Route path="/purchase" element={<Purchase />} />
  <Route path="/business-details" element={<BusinessDetails />} />
</Routes>
    </Router>
  );
}

export default App;
